import { initializeApp } from 'firebase/app';
import { getAuth, GoogleAuthProvider, signInWithPopup, RecaptchaVerifier, signInWithPhoneNumber } from 'firebase/auth';

const firebaseConfig = {
  apiKey: process.env.REACT_APP_FIREBASE_API_KEY,
  authDomain: process.env.REACT_APP_FIREBASE_AUTH_DOMAIN,
  projectId: process.env.REACT_APP_FIREBASE_PROJECT_ID,
  storageBucket: process.env.REACT_APP_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: process.env.REACT_APP_FIREBASE_MESSAGING_SENDER_ID,
  appId: process.env.REACT_APP_FIREBASE_APP_ID
};

const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const googleProvider = new GoogleAuthProvider();
googleProvider.setCustomParameters({ prompt: 'select_account' });

// ─── Google Sign-In ───────────────────────────────────────
export const signInWithGoogle = async () => {
  const result = await signInWithPopup(auth, googleProvider);
  const idToken = await result.user.getIdToken();
  return idToken;
};

// ─── Phone OTP via Firebase ───────────────────────────────
export const setupRecaptcha = (buttonId) => {
  window.recaptchaVerifier = new RecaptchaVerifier(auth, buttonId, {
    size: 'invisible',
    callback: () => {}
  });
};

export const sendPhoneOTP = async (phone) => {
  if (!window.recaptchaVerifier) {
    throw new Error('Recaptcha not initialized');
  }
  const result = await signInWithPhoneNumber(auth, phone, window.recaptchaVerifier);
  window.confirmationResult = result;
  return result;
};

export const verifyPhoneOTP = async (otp) => {
  if (!window.confirmationResult) throw new Error('No OTP sent yet');
  const result = await window.confirmationResult.confirm(otp);
  const idToken = await result.user.getIdToken();
  return { idToken, user: result.user };
};

export default app;
